// -- titlePg (§17.6.18) ---------------------------------------------------

/// ISO 29500-1 §17.6.18: w:titlePg enables distinct first-page header/footer.
///
/// The fixture has a sectPr with w:titlePg element. This boolean flag should
/// be accessible in SectionProperties so the renderer knows to use different
/// headers/footers for the first page of the section.
#[test]
fn audit_title_page_flag() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "title-page");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one mid-document section with titlePg"
    );

    let props = section_props[0];
    assert_eq!(
        props.title_page,
        Some(true),
        "titlePg should be parsed as Some(true)"
    );
}

