// -- pgSz w:code (§17.6.14) -----------------------------------------------

/// ISO 29500-1 §17.6.14: pgSz code attribute specifies standard paper size.
///
/// The fixture has pgSz with code=9 (A4). The code attribute supplements
/// the explicit w/h dimensions and identifies the standard paper size.
#[test]
fn audit_paper_size_code() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "paper-size-code");

    let section_props = section_paragraphs(&doc);
    assert!(
        !section_props.is_empty(),
        "should have at least one mid-document section with pgSz code"
    );

    let props = section_props[0];

    // Width/height should be parsed (already works)
    assert_eq!(
        props.page_width,
        Some(11906),
        "page width should be 11906 (A4), got {:?}",
        props.page_width
    );
    assert_eq!(
        props.page_height,
        Some(16838),
        "page height should be 16838 (A4), got {:?}",
        props.page_height
    );

    assert_eq!(
        props.paper_size_code,
        Some(9),
        "paper_size_code should be Some(9) for A4, got {:?}",
        props.paper_size_code
    );
}

